sql:
SELECT * 
FROM economic_data
WHERE year = 2020;

SELECT 
    (SELECT realgdp FROM economic_data WHERE data_id = 0) / 
    (SELECT realgdp FROM economic_data WHERE data_id = 1) AS change_ratio;

SELECT pop
FROM economic_data
WHERE data_id = (SELECT MAX(data_id) FROM economic_data);

SELECT DISTINCT created_by_user_id AS user_id
FROM reports
WHERE access_count > 10;

SELECT MAX(realgdp) AS highest_real_gdp
FROM economic_data
WHERE year = 1960 AND quarter = 2 AND is_latest = 1;
